content.text:
You are an expert landing page analyst and direct response copywriter. Analyze this landing page screenshot and extract its complete structure, copy patterns, and design system.

The page type is: {{ $node['Webhook: LP Swipe'].json.body.page_type }}

Output ONLY valid JSON with no markdown:
{
  "section_structure": [
    {
      "index": 0,
      "type": "hero|problem|agitation|solution|features|testimonials|social_proof|faq|cta|guarantee|urgency|story|mechanism|comparison|pricing",
      "description": "Brief description of what this section does",
      "word_count_estimate": 50,
      "purpose": "What persuasion goal this section achieves"
    }
  ],
  "copy_blocks": [
    {
      "section": "Section name",
      "headline": "Main headline text if visible",
      "subheadline": "Subheadline if present",
      "body": "Body copy summary",
      "cta": "CTA text if present in this section"
    }
  ],
  "design_patterns": {
    "layout": "Single column / Two column / etc",
    "spacing": "Tight / Moderate / Generous",
    "imagery_style": "Photography / Illustration / Icons / Mixed",
    "social_proof_placement": "Where social proof appears in the flow",
    "cta_strategy": "How CTAs are positioned throughout",
    "visual_hierarchy": "How attention is guided"
  },
  "color_scheme": {
    "primary": "#hex",
    "secondary": "#hex",
    "accent": "#hex",
    "background": "#hex",
    "text": "#hex",
    "cta_color": "#hex"
  },
  "typography": {
    "headline_font": "Font family or style description",
    "body_font": "Font family or style description",
    "sizes": "Large headlines / Medium body / etc",
    "weights": "Bold headlines / Regular body / etc"
  },
  "cta_placements": [
    {
      "location": "Where in the page flow",
      "text": "CTA button text",
      "style": "Color, shape, size",
      "urgency_level": "none|low|medium|high"
    }
  ],
  "recreation_prompt": "A DETAILED prompt to recreate this exact landing page style. Include: overall layout structure, section ordering, typography choices, color usage, spacing rhythm, imagery approach, CTA positioning, copy tone and flow. This will be used by an AI to generate a new page in this exact style but with different brand/offer content. Be extremely specific about the visual design system.",
  "masterson_mapping": {
    "awareness_level": "unaware|problem_aware|solution_aware|product_aware|most_aware",
    "emotional_flow": "How emotions progress through the page (e.g., fear → hope → trust → urgency)",
    "proof_stacking": "How proof elements build on each other",
    "objection_handling": "Where and how objections are addressed",
    "persuasion_techniques": ["List of techniques used: scarcity, social proof, authority, reciprocity, etc."]
  }
}

parameters.functionCode:
const data = $input.first().json;
const webhookData = $node['Webhook: LP Swipe'].json.body;

try {
  let responseText = data.content[0].text;
  responseText = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const analysis = JSON.parse(responseText);

  return [{
    json: {
      screenshot_url: webhookData.screenshot_url,
      page_type: webhookData.page_type || 'advertorial',
      niche: webhookData.niche || 'general',
      source_url: webhookData.source_url || null,
      section_structure: analysis.section_structure || [],
      copy_blocks: analysis.copy_blocks || [],
      design_patterns: analysis.design_patterns || {},
      color_scheme: analysis.color_scheme || {},
      typography: analysis.typography || {},
      cta_placements: analysis.cta_placements || [],
      recreation_prompt: analysis.recreation_prompt || '',
      masterson_mapping: analysis.masterson_mapping || {}
    }
  }];
} catch (e) {
  return [{
    json: {
      screenshot_url: webhookData.screenshot_url,
      page_type: webhookData.page_type || 'advertorial',
      niche: webhookData.niche || 'general',
      notes: 'Analysis parsing failed: ' + (data.content?.[0]?.text || e.message)
    }
  }];
}
